def constant(x):              # O(1)
    return x * 2

def linear(xs):               # O(n)
    return sum(xs)

def log_n(sorted_xs, target):  # O(log n) — binary search
    lo, hi = 0, len(sorted_xs)
    while lo < hi:
        mid = (lo + hi) // 2
        if sorted_xs[mid] < target:
            lo = mid + 1
        else:
            hi = mid
    return lo

def quadratic(xs):            # O(n²)
    pairs = 0
    for a in xs:
        for b in xs:
            if a < b:
                pairs += 1
    return pairs

def nlogn(xs):                # O(n log n)
    return sorted(xs)

def exponential(xs):          # O(2ⁿ) — all subsets
    if not xs: return [[]]
    rest = exponential(xs[1:])
    return rest + [[xs[0]] + s for s in rest]
